INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 0, 0, 2, 0, 0, 1, 11130401, "vo_minigame_1012_incorrect_123", 1304, 2, 0.0, "忘れちゃダメよ？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 0, 0, 1, 0, 0, 1, 11130501, "vo_minigame_1012_incorrect_126", 1305, 1, 0.0, "全部が間違いじゃないわ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 10, 1, 8, 4, 10, 1, 11300101, "vo_minigame_1012_result_1000", 3001, 7, 3.18, "フフ、全問正解よ！\nちゃんと勉強してるみたいで\n感心だわ♪");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 10, 1, 7, 10, 10, 1, 11300102, "vo_minigame_1012_result_1001", 3001, 8, 3.33, "すごいじゃない…全問正解よ！\nま、当然といや当然よね～\nだってあたしが\n教えてやってんだから♪");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 10, 1, 1, 10, 10, 1, 11300103, "vo_minigame_1012_result_1002", 3001, 8, 5.41, "全問正解！　パチパチパチ～♪\nこの難易度はもう完璧じゃない？\n次はもっと難しい問題に挑戦よ！\nあんたならできるって！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 10, 2, 8, 10, 10, 1, 11300104, "vo_minigame_1012_result_1003", 3001, 5, 8.11, "へえ…難しい問題を選んだのに\n全問正解できてるじゃない！！\nちょっとあんたすごすぎだわ…！\nパーフェクトよパーフェクト！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 10, 2, 5, 0, 10, 1, 11300105, "vo_minigame_1012_result_1004", 3001, 10, 1.31, "まる…まる…全部まる！\n難しい問題なのに全問正解よ…！\n驚いた…あんたいつの間に、\nこんなに勉強してたのよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 10, 2, 8, 0, 10, 1, 11300106, "vo_minigame_1012_result_1005", 3001, 9, 4.93, "ここまで完璧に正解されちゃうと\nちょっと悔しいわね…！\nけど素直に褒めてやるわ！\nえらい、えらい、えら～い！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 10, 3, 8, 4, 10, 1, 11300107, "vo_minigame_1012_result_1006", 3001, 5, 2.99, "すごい…あんたパーフェクトよ！\nこのままいけば次の試験、\n学年一位も夢じゃないかもね！\n楽しみだわ～♪");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 10, 3, 7, 4, 10, 1, 11300108, "vo_minigame_1012_result_1007", 3001, 8, 8.37, "満点よ！　フフ、もうあんたに\n教えることはなにもないわ…！\n逆にあたしがあんたに教わりたい\nくらいよ！　…ね、先生♪");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 10, 3, 5, 8, 10, 1, 11300109, "vo_minigame_1012_result_1008", 3001, 7, 5.32, "全・問・正・解！\n超難問揃いなのにすごいわね…！\nもしかしてだけど、\nあんたって天才！？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 9, 1, 1, 4, 7, 1, 11300110, "vo_minigame_1012_result_1009", 3001, 7, 4.77, "お、かなりいい点数ね～！\nあたしも教えがいがあるわ♪\nさ、まだまだ勉強するわよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 9, 1, 7, 4, 7, 1, 11300111, "vo_minigame_1012_result_1010", 3001, 8, 2.97, "うん、いい感じで点取れてるわ！\nこの調子で次は、\n満点を見せてほしいわね！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 9, 1, 1, 0, 7, 1, 11300112, "vo_minigame_1012_result_1011", 3001, 5, 3.47, "あ～惜しい！\nもうちょっとで満点じゃない！\n次はパーフェクトいけるわ！\n頑張りましょ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 9, 2, 7, 4, 7, 1, 11300113, "vo_minigame_1012_result_1012", 3001, 8, 5.32, "すごい、かなりできてるわよ！\n難しい問題なのにやるじゃない！\nあとは目指せ、満点ね！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 9, 2, 7, 10, 7, 1, 11300114, "vo_minigame_1012_result_1013", 3001, 8, 6.49, "うん、かなりいい感じよ！\nあんたには赤点の心配なんて\nまーったくなさそうね♪\nでも勉強はやめさせないけど！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 9, 2, 1, 0, 7, 1, 11300115, "vo_minigame_1012_result_1014", 3001, 5, 3.56, "あーあとちょっとで\n全問正解だったのに！\n難しい問題だけどあんたなら\n次は満点狙えるわ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 9, 3, 1, 10, 7, 1, 11300116, "vo_minigame_1012_result_1015", 3001, 8, 5.67, "うん、ほとんど正解よ！\nこんな難しい問題なのに、\nすごいじゃない！\nやっぱりあんた只者じゃないわ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 9, 3, 1, 10, 7, 1, 11300117, "vo_minigame_1012_result_1016", 3001, 7, 2.85, "着実に成長してるって感じね？\nあんたならこの難問でも、\nいつか満点取れちゃうかも…！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 9, 3, 1, 0, 7, 1, 11300118, "vo_minigame_1012_result_1017", 3001, 5, 3.88, "うわー惜しいわね！\nもうちょっとで満点よ？\nま、あたしでも悩む難問だから、\nこの点数は胸を張っていいわ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 6, 1, 1, 0, 4, 1, 11300119, "vo_minigame_1012_result_1018", 3001, 3, 4.12, "正解率は半分くらいか～\n悪くはないんだけど、あんたなら\nこんなもんじゃないでしょ？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 6, 1, 1, 0, 4, 1, 11300120, "vo_minigame_1012_result_1019", 3001, 9, 4.34, "んーはっきり言っちゃうと\n中途半端な点数ね…\nまあいいわ！こっからガンガン\n点数上げていくわよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 6, 1, 1, 0, 4, 1, 11300121, "vo_minigame_1012_result_1020", 3001, 3, 3.15, "う～ん、正直物足りない点数ね！\nあんたには期待してんだから、\nもっと頑張んなさい！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 6, 2, 1, 0, 4, 1, 11300122, "vo_minigame_1012_result_1021", 3001, 9, 5.3, "半分くらいの正解率か\n難しい問題だから仕方ないわね…\nでもあんたはもっとできる！\nだってあたしがついてんのよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 6, 2, 1, 0, 4, 1, 11300123, "vo_minigame_1012_result_1022", 3001, 8, 2.55, "うん、そこそこできんじゃない！\n頑張って勉強して\nさらに上を目指しましょ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 6, 2, 7, 0, 4, 1, 11300124, "vo_minigame_1012_result_1023", 3001, 1, 4.19, "難問なのにこの正解率は\nよくやってる方よね！\nでもこんなところで\n満足してんじゃないわよ！？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 6, 3, 1, 0, 4, 1, 11300125, "vo_minigame_1012_result_1024", 3001, 7, 3.43, "難問なのに半分くらい正解\nできてんじゃない♪\nこの調子でもっと学力\n上げていきましょ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 6, 3, 1, 0, 4, 1, 11300126, "vo_minigame_1012_result_1025", 3001, 1, 0.0, "よし、平均点ってとこね！\nちゃんと勉強してるみたいで\n安心したわ～♪");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 6, 3, 7, 0, 4, 1, 11300127, "vo_minigame_1012_result_1026", 3001, 8, 3.72, "難問揃いでこの正解率は\n大したもんよ！\nま、もっといい点取りたいんなら\n勉強、付き合ったげるわ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3, 1, 2, 1, 1, 1, 11300128, "vo_minigame_1012_result_1027", 3001, 3, 3.5, "なるほど…\nこれは教えがいがあるわね\nビシバシ鍛えてやるから\n覚悟しなさい！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3, 1, 2, 1, 1, 1, 11300129, "vo_minigame_1012_result_1028", 3001, 4, 3.25, "ちょっとあんた、\n全然できてないじゃない！\n…まさかこれが本気だなんて\n言わないわよね～？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3, 1, 2, 0, 1, 1, 11300130, "vo_minigame_1012_result_1029", 3001, 3, 4.62, "うーん……適当に答えても\nこれくらい正解できるわよ？\nちょっと本腰入れて\n教えないとね……！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3, 2, 1, 0, 1, 1, 11300131, "vo_minigame_1012_result_1030", 3001, 9, 4.5, "…ま、まあこの問題は\nあんたには難しすぎたのかもね\nちょっとずつでいいから、\nレベルアップしていきましょ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3, 2, 3, 9, 1, 1, 11300132, "vo_minigame_1012_result_1031", 3001, 3, 0.01, "んー結構ミスっちゃってるわね…\nこのまま続けるのもいいけど、\n簡単な問題からやり直すのも\nありかもよ～？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3, 2, 9, 9, 1, 1, 11300133, "vo_minigame_1012_result_1032", 3001, 9, 0.01, "あらら、あんたにはちょっと\n難しすぎたかしら…？\nもう一回やり直しましょうか！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3, 3, 3, 6, 1, 1, 11300134, "vo_minigame_1012_result_1033", 3001, 3, 0.01, "うーん、残念な結果ね…\n超難問だから仕方ないけど\n無理せず簡単な問題から挑戦\nしてもいいかもよ？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3, 3, 9, 0, 1, 1, 11300135, "vo_minigame_1012_result_1034", 3001, 3, 2.97, "正解率はかなり悪いわね…\nまあ難しい問題だもんね…！\nそのチャレンジ精神は買うわ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3, 3, 1, 0, 1, 1, 11300136, "vo_minigame_1012_result_1035", 3001, 3, 3.1, "なんとか０点は免れたわね…\n難問揃いだけど、\nもっと頑張っていきましょ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 0, 1, 2, 1, 0, 1, 11300137, "vo_minigame_1012_result_1036", 3001, 6, 4.31, "…あんたさ、０点なんて\n逆に取るの難しいわよ！？\nまさか狙ったわけじゃ\nないでしょーね～！？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 0, 1, 2, 1, 0, 1, 11300138, "vo_minigame_1012_result_1037", 3001, 2, 0.1, "０点って…\nあんたふざけてんの！？\nちゃんとやらないなら\n電撃魔法くらわせるわよ！？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 0, 1, 3, 9, 0, 1, 11300139, "vo_minigame_1012_result_1038", 3001, 9, 4.23, "もしかしたらあんたは\n勉強向いてないのかもね…\n…勉強だけがすべてじゃないわ\n違うとこで頑張りましょ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 0, 2, 2, 0, 0, 1, 11300140, "vo_minigame_1012_result_1039", 3001, 3, 4.38, "怒んないから正直に言って？\n…ふざけて答えたでしょ？\nほら、正直に\n言・い・な・さ・い？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 0, 2, 2, 0, 0, 1, 11300141, "vo_minigame_1012_result_1040", 3001, 8, 3.58, "あんたの点数は～～…\n…はい！　０てーん！！\n…って、ふざけんなーー！！！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 0, 2, 2, 1, 0, 1, 11300142, "vo_minigame_1012_result_1041", 3001, 4, 2.02, "０点ってどういうこと！？\nいやあんた、逆にすごいわよ！？\n目つぶってやったとしても\n１点は取れるから！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 0, 3, 1, 9, 0, 1, 11300143, "vo_minigame_1012_result_1042", 3001, 9, 5.53, "あちゃー……残念だけど０点よ\nちょっと難しすぎたかもねー…\n…ま、こんなこともあるわ！\n気を落とさなくていいわよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 0, 3, 1, 9, 0, 1, 11300144, "vo_minigame_1012_result_1043", 3001, 3, 4.4, "かなりの難問とはいえ、\n０点はちょっと寂しいわね…\nでもま、逆に考えるのよ！\nあんたには伸びしろしかないわ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 0, 3, 1, 0, 0, 1, 11300145, "vo_minigame_1012_result_1044", 3001, 3, 5.35, "０点かー…うん、ごめん…\n慰めの言葉が浮かばないわ！\n……ま、次があるから\n切り替えてくのよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 0, 0, 8, 0, 0, 1, 12120101, "vo_minigame_1012_correct_132", 1201, 8, 0.0, "OK！");
