INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 30000, 0, 1, 3, 20000, 1, 12170102, "vo_minigame_1012_time_101", 1701, 1, 0.01, "もうすぐ終わりよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, -1, 1, 1, 10, 20, 1, 12300101, "vo_minigame_1012_result_1045", 3001, 7, 3.74, "はい、よくできました！\n基礎はもう完璧ね！\n次はもっと難しい問題にも\nチャレンジしちゃいなさいよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, -1, 1, 9, 0, 20, 1, 12300102, "vo_minigame_1012_result_1046", 3001, 1, 3.85, "なによあんた、走り出したペンが\n止まらないって感じ？\nったくシンプルにすごいじゃない\n花丸あげるわ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, -1, 1, 5, 8, 20, 1, 12300103, "vo_minigame_1012_result_1047", 3001, 5, 0.01, "すごい点数ね…！\nあんた勉強してないとか言って\nホントはめちゃくちゃやってる\nパターンのやつね！？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, -1, 2, 7, 4, 20, 1, 12300104, "vo_minigame_1012_result_1048", 3001, 8, 2.86, "勉強の成果、\nちゃんとでてんじゃない！\nあたしもあんたの先生として、\n鼻が高いわ～♪");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, -1, 2, 3, 9, 20, 1, 12300105, "vo_minigame_1012_result_1049", 3001, 5, 2.02, "オッケー！　もう十分よ！\nこれ以上でき過ぎちゃったら、\nあたしが教える必要なくなるわ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, -1, 2, 1, 0, 20, 1, 12300106, "vo_minigame_1012_result_1050", 3001, 5, 4.46, "難しい問題を選んだつもりなのに\nすごい正解数ね…！\nでもまだ上がある…\n次は最難関に挑戦よ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, -1, 3, 4, 7, 20, 1, 12300107, "vo_minigame_1012_result_1051", 3001, 5, 6.85, "すごいすごいとは思ってたけど、\nあんた勉強も完璧なの…？\nそりゃみんなあんたに惚れ…\nや、な、なんでもない！！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, -1, 3, 9, 0, 20, 1, 12300108, "vo_minigame_1012_result_1052", 3001, 5, 3.79, "この問題、あたしでも悩む\n超難問なのに…\nふふっ、もう褒めるしかないわ！\n大変よくできました！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, -1, 3, 4, 7, 20, 1, 12300109, "vo_minigame_1012_result_1053", 3001, 4, 0.01, "別に顔赤くなんてなってない！\n頭がいい人が好きとか…\nかっこいいとか…\n…思ってないからね！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, -1, 1, 5, 0, 20, 1, 12300110, "vo_minigame_1012_result_1054", 3001, 5, 0.0, "スピードも正確さも完璧…\n文句なしの満点だわ！\nあんた将来、とんでもない人に\nなっちゃうんじゃない！？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, -1, 2, 5, 0, 20, 1, 12300112, "vo_minigame_1012_result_1054", 3001, 5, 0.0, "スピードも正確さも完璧…\n文句なしの満点だわ！\nあんた将来、とんでもない人に\nなっちゃうんじゃない！？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, -1, 3, 5, 0, 20, 1, 12300114, "vo_minigame_1012_result_1054", 3001, 5, 0.0, "スピードも正確さも完璧…\n文句なしの満点だわ！\nあんた将来、とんでもない人に\nなっちゃうんじゃない！？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 19, 1, 7, 10, 15, 1, 12300116, "vo_minigame_1012_result_1056", 3001, 5, 3.0, "おお～かなり正解できてるわね！\nこの調子でもっとすごい点\n目指しちゃうわよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 19, 1, 8, 10, 15, 1, 12300117, "vo_minigame_1012_result_1057", 3001, 8, 0.01, "うん、バッチリいい感じよ！\nちゃんと勉強してるみたいで\n関心関心♪");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 19, 1, 8, 0, 15, 1, 12300118, "vo_minigame_1012_result_1058", 3001, 5, 4.01, "え、こんなにいい点取れたのに\nまだ満足してないの？\nなによその向上心…\nいいじゃない！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 19, 2, 7, 10, 15, 1, 12300119, "vo_minigame_1012_result_1059", 3001, 8, 2.83, "スピードも正解数もいい感じよ！\nねえねえ、この調子で\nてっぺん目指しちゃう？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 19, 2, 10, 0, 15, 1, 12300120, "vo_minigame_1012_result_1060", 3001, 10, 0.0, "この難易度でも\nスラスラ答えちゃうなんて…\nあんたって\nほんとすごいやつよね…！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 19, 2, 7, 4, 15, 1, 12300121, "vo_minigame_1012_result_1061", 3001, 8, 3.66, "これだけ正解できたら\n勉強も楽しいわよね♪\nさ、まだまだ続けるわよ～！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 19, 3, 8, 0, 15, 1, 12300122, "vo_minigame_1012_result_1062", 3001, 5, 3.28, "あんた、この成績\nまぐれじゃないわよね…！\nこれだけできたら\n大したもんだわ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 19, 3, 1, 0, 15, 1, 12300123, "vo_minigame_1012_result_1063", 3001, 8, 2.7, "すごい！　とってもいい成績よ！\nこの難問も、あんたにかかりゃ\nイチコロってやつ？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 19, 3, 9, 9, 15, 1, 12300124, "vo_minigame_1012_result_1064", 3001, 5, 3.98, "あんた…もしかして\nあたしより点数いいかも？\nあ、あたしもあんたを見習って\n勉強しないとね…！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 14, 1, 1, 0, 10, 1, 12300131, "vo_minigame_1012_result_1067", 3001, 7, 2.51, "うん、なかなかいい点数よ！\nでもまだまだ頑張れるわよね？\nはい、次いきましょ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 14, 1, 7, 0, 10, 1, 12300132, "vo_minigame_1012_result_1068", 3001, 1, 4.16, "十分優秀な成績だけど\nあんたならもっとできる！\nさ、頑張って勉強するわよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 14, 1, 7, 0, 10, 1, 12300133, "vo_minigame_1012_result_1069", 3001, 8, 2.07, "うん、いい感じね！\nこの調子で少しずつ、\n正解数を増やしてくわよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 14, 2, 1, 0, 10, 1, 12300134, "vo_minigame_1012_result_1070", 3001, 8, 3.51, "難問揃いなのに、\nけっこーいい感じじゃない！\nちゃんとできてるから\n自信もっていいわよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 14, 2, 1, 0, 10, 1, 12300135, "vo_minigame_1012_result_1071", 3001, 1, 0.0, "難しい問題でも基礎は大事よ！\nこの調子でどんどん\n点数上げていきましょう！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 14, 2, 7, 0, 10, 1, 12300136, "vo_minigame_1012_result_1072", 3001, 1, 4.3, "10問以上取れてるわね！\nえ、まだ物足りない？\nフフ、じゃあもっと上\n目指しちゃう？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 14, 3, 7, 0, 10, 1, 12300137, "vo_minigame_1012_result_1073", 3001, 8, 4.47, "うん、この難問でこの点数は\n十分すぎる出来よね！\nま、あんたならもっといい点\n目指しちゃうんだろうけど♪");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 14, 3, 9, 0, 10, 1, 12300138, "vo_minigame_1012_result_1074", 3001, 8, 3.68, "はいお疲れ～\nなかなか良い点数じゃない\n…あたしも勉強しないとね！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 14, 3, 1, 0, 10, 1, 12300139, "vo_minigame_1012_result_1075", 3001, 5, 3.34, "おお～10問以上\n正解してんじゃない！\nあんたやっぱり\nただ者じゃないわね～");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 14, 1, 8, 0, 10, 1, 12300141, "vo_minigame_1012_result_1077", 3001, 1, 6.58, "うん正解率は申し分なしね！\nあとはもっと早く解ければ\nもっと点数は伸びてくわよ！\nこの調子で頑張っていきましょ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 14, 2, 8, 0, 10, 1, 12300143, "vo_minigame_1012_result_1077", 3001, 1, 6.58, "うん正解率は申し分なしね！\nあとはもっと早く解ければ\nもっと点数は伸びてくわよ！\nこの調子で頑張っていきましょ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 14, 3, 8, 0, 10, 1, 12300145, "vo_minigame_1012_result_1077", 3001, 1, 6.58, "うん正解率は申し分なしね！\nあとはもっと早く解ければ\nもっと点数は伸びてくわよ！\nこの調子で頑張っていきましょ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 9, 1, 7, 0, 5, 1, 12300146, "vo_minigame_1012_result_1078", 3001, 1, 4.24, "ふ～ん、まあまあの出来だわ\n悪くはないんだけど…あんたには\nもっともっと期待してるわ～");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 9, 1, 1, 0, 5, 1, 12300147, "vo_minigame_1012_result_1079", 3001, 7, 4.74, "うん、頑張ったけど…\n正直もっと正解できるかもね～？\nこんなのあんたには通過点！\nさらに良い点目指してみない？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 9, 1, 1, 0, 5, 1, 12300148, "vo_minigame_1012_result_1080", 3001, 1, 0.0, "まあまあな点数だけど、\n自分的に手ごたえはどう？\nダメだって思ってんなら、\nまだまだ伸びる余地ありね！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 9, 2, 1, 0, 5, 1, 12300149, "vo_minigame_1012_result_1081", 3001, 8, 2.21, "うん、中々の出来ね！\nでもあんたはもっといい点\n取れるはずよ！\nもっと頑張りましょうか！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 9, 2, 1, 0, 5, 1, 12300150, "vo_minigame_1012_result_1082", 3001, 3, 2.46, "ん～はっきり言って微妙ね！\nま、難しい問題だし、\n勉強すれば\n点数は上がっていくと思うわ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 9, 2, 1, 0, 5, 1, 12300151, "vo_minigame_1012_result_1083", 3001, 3, 2.94, "ん～…\n10点には届かなかったか～\n次は10点越え目指して\n頑張ってみない？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 9, 3, 1, 0, 5, 1, 12300152, "vo_minigame_1012_result_1084", 3001, 7, 4.19, "はいお疲れ～\n点数的にはまあまあってとこね！\nま、超難問だし頑張ったわよ");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 9, 3, 1, 0, 5, 1, 12300153, "vo_minigame_1012_result_1085", 3001, 1, 0.0, "うん、かなり難しい問題なのに\n最後までやり遂げたわね\n次はもっといい点目指してみる？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 9, 3, 1, 0, 5, 1, 12300154, "vo_minigame_1012_result_1086", 3001, 3, 2.63, "ちょっとミスが多かったかもね～\nでも間違えた所は復習して\n次は正解するわよー！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 4, 1, 1, 0, 1, 1, 12300155, "vo_minigame_1012_result_1087", 3001, 3, 5.53, "あら…あんまり良くない点数ね～\nどうしたの、調子でも悪かった？\n次はもっと頑張りましょうか");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 4, 1, 3, 9, 1, 1, 12300156, "vo_minigame_1012_result_1088", 3001, 3, 0.01, "ん～…正解数は\n物足りないわね～\nもうちょっと勉強の時間\n増やしちゃおっか？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 4, 1, 1, 3, 1, 1, 12300157, "vo_minigame_1012_result_1089", 3001, 3, 4.15, "ん～…あんたならもうちょと\nいい点取れんでしょ～？\nもっと頑張んなさいよ\n期待してやってんだからさ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 4, 2, 9, 9, 1, 1, 12300158, "vo_minigame_1012_result_1090", 3001, 9, 0.01, "ん～今のあんたには、\nこの問題は難しかったかしら…\n難易度下げてチャレンジするのも\nありかもね～？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 4, 2, 1, 0, 1, 1, 12300159, "vo_minigame_1012_result_1091", 3001, 3, 5.37, "あんまり出来は良くないわね～\n難しい問題だししょうがないけど\n次はもっと頑張ってほしいわ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 4, 2, 1, 0, 1, 1, 12300160, "vo_minigame_1012_result_1092", 3001, 3, 1.44, "なるほど…\nちょっと苦手な問題が多かった？\nもう一度チャレンジ\nしてみましょうか～");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 4, 3, 3, 0, 1, 1, 12300161, "vo_minigame_1012_result_1093", 3001, 3, 0.0, "んん～…問題が難しすぎた？\n無理に難しい問題続けるより、\n難易度下げた方が\n勉強の効率良いかもよ～？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 4, 3, 9, 3, 1, 1, 12300162, "vo_minigame_1012_result_1094", 3001, 3, 2.91, "…あんまり点数取れなかったわね\nこれはあたしにも難しい問題だし\nそう落ち込まなくても大丈夫！\n次頑張りましょ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 4, 3, 1, 0, 1, 1, 12300163, "vo_minigame_1012_result_1095", 3001, 5, 2.61, "ごめん、ちょっと難しすぎた？\nもう一度チャレンジするも良し、\n難易度を下げるも良し、\nあんたがやる気なら付き合うわ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 0, 1, 2, 1, 0, 1, 12300164, "vo_minigame_1012_result_1096", 3001, 4, 3.63, "ちょっとあんた…\nやる気ないわよね～！？\n次こんな点数取ったら\n怒るわよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 0, 1, 2, 1, 0, 1, 12300165, "vo_minigame_1012_result_1097", 3001, 6, 4.16, "はあ…自分で何点取ったか\n分かってるわよね～…？\n０点よ０点！　舐めてんの！？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 0, 1, 3, 6, 0, 1, 12300166, "vo_minigame_1012_result_1098", 3001, 3, 0.01, "うう～頭痛い…\nあんたのせいよ！\nなに０点って！\nはあ、このままじゃ赤点よ～…");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 0, 2, 2, 0, 0, 1, 12300167, "vo_minigame_1012_result_1099", 3001, 6, 5.75, "ねえ、あんた本気でやったの？\nまさか適当にやるわけないわよね\n…分かった、\nもう一回チャレンジするのよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 0, 2, 2, 1, 0, 1, 12300168, "vo_minigame_1012_result_1100", 3001, 4, 5.64, "あ…あんた、０点よ０点…！\nあたしの教え方が悪かった…？\n…燃えてきたわ！\n絶対あんたの学力上げてやる！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 0, 2, 4, 8, 0, 1, 12300169, "vo_minigame_1012_result_1101", 3001, 8, 5.73, "ちょっと待って採点ミスかも…\n…いや合ってるわね。はい０点\n…って０点！？\nふざけんなーー！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 0, 3, 3, 1, 0, 1, 12300170, "vo_minigame_1012_result_1102", 3001, 5, 5.32, "あらら…０点よ\nま、難しい問題だしね…\n…つっても０点は無いわ！\n一問くらい正解しなさいよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 0, 3, 9, 9, 0, 1, 12300171, "vo_minigame_1012_result_1103", 3001, 3, 2.37, "残念だけど０点よ\nま、まあ前向きにとらえるなら、\n今が底よ！　どん底！\nあとは上がってくだけね！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 0, 3, 1, 3, 0, 1, 12300172, "vo_minigame_1012_result_1104", 3001, 9, 4.25, "…かなり出来が悪いわね\n一旦休憩しましょうか？\nリフレッシュして頭切り替えて\nもう一度頑張りましょう！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 0, 0, 7, 0, 0, 1, 13100101, "vo_minigame_1012_gamestart_100", 1001, 7, 0.0, "さ、勉強を始めるわよ");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 0, 0, 1, 0, 0, 1, 13100102, "vo_minigame_1012_gamestart_101", 1001, 1, 0.0, "よし、勉強の成果を見てやるわ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 0, 0, 7, 0, 0, 1, 13100103, "vo_minigame_1012_gamestart_102", 1001, 1, 1.82, "じゃあ試験するわよ。はい教科書閉じて！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, -1, 0, 8, 4, 3, 1, 13100201, "vo_minigame_1012_gamestart_103", 1002, 8, 0.01, "やる気マンマンじゃない！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, -1, 0, 1, 0, 3, 1, 13100202, "vo_minigame_1012_gamestart_104", 1002, 1, 0.0, "よし、じゃあもう一回やるわよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 1, 0, 0, 0, 1, 1, 13100301, "vo_minigame_1012_gamestart_105", 1003, 0, 0.0, "普通の難易度よ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 1, 0, 7, 0, 1, 1, 13100302, "vo_minigame_1012_gamestart_106", 1003, 7, 0.0, "まずは基本からね！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 2, 0, 10, 0, 2, 1, 13100303, "vo_minigame_1012_gamestart_107", 1003, 10, 0.0, "難しい問題に挑戦するのね！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 2, 0, 8, 0, 2, 1, 13100304, "vo_minigame_1012_gamestart_108", 1003, 1, 0.67, "よし、あんたならできるわ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 3, 0, 5, 0, 3, 1, 13100305, "vo_minigame_1012_gamestart_109", 1003, 5, 0.0, "あたしでも手こずる難問揃いよ…！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 3, 0, 2, 0, 3, 1, 13100306, "vo_minigame_1012_gamestart_110", 1003, 2, 0.0, "激ムズだけど頑張んなさい！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 0, 0, 7, 0, 0, 1, 13100401, "vo_minigame_1012_gamestart_111", 1004, 7, 0.0, "鉄は熱いうちに打て、\n…ってね♪");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 0, 0, 1, 0, 0, 1, 13100402, "vo_minigame_1012_gamestart_112", 1004, 1, 0.0, "よし、もっぺんやるわよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 0, 0, 9, 0, 0, 1, 13100501, "vo_minigame_1012_gamestart_113", 1005, 9, 0.0, "スズナもちゃんと勉強してるみたいね～");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 0, 0, 3, 0, 0, 1, 13100502, "vo_minigame_1012_gamestart_114", 1005, 3, 0.0, "あんたがスズナの\n先生？　…ふーん");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 0, 0, 1, 0, 0, 1, 13110101, "vo_minigame_1012_start_100", 1101, 1, 0.0, "問題！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 0, 0, 1, 0, 0, 1, 13110102, "vo_minigame_1012_start_101", 1101, 1, 0.0, "いくわよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 0, 0, 7, 0, 0, 1, 13110103, "vo_minigame_1012_start_102", 1101, 7, 0.0, "解けるかしら？");
