INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 0, 0, 1, 0, 0, 1, 13110203, "vo_minigame_1012_start_105", 1102, 1, 0.0, "取り返すのよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 4, 0, 1, 0, 2, 1, 13110301, "vo_minigame_1012_start_106", 1103, 1, 0.0, "さあ次よ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 4, 0, 1, 0, 2, 1, 13110302, "vo_minigame_1012_start_107", 1103, 1, 0.0, "落ち着いてね！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 4, 0, 7, 0, 2, 1, 13110303, "vo_minigame_1012_start_108", 1103, 7, 0.0, "これは解ける？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 7, 0, 2, 0, 5, 1, 13110304, "vo_minigame_1012_start_109", 1103, 2, 0.0, "まだ気を抜かないで！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 7, 0, 1, 0, 5, 1, 13110305, "vo_minigame_1012_start_110", 1103, 1, 0.0, "ほら、次いくわよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 7, 0, 8, 0, 5, 1, 13110306, "vo_minigame_1012_start_111", 1103, 8, 0.0, "まだまだ続くわよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 10, 0, 2, 0, 8, 1, 13110307, "vo_minigame_1012_start_112", 1103, 2, 0.0, "最後まで集中よ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 10, 0, 8, 0, 8, 1, 13110308, "vo_minigame_1012_start_113", 1103, 8, 0.0, "ラストスパート！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 10, 0, 1, 0, 8, 1, 13110309, "vo_minigame_1012_start_114", 1103, 1, 0.0, "走り切って！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 2, 0, 2, 0, 2, 1, 13110401, "vo_minigame_1012_start_115", 1104, 2, 0.0, "適当に選ぶんじゃないわよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 2, 0, 7, 0, 2, 1, 13110402, "vo_minigame_1012_start_116", 1104, 7, 0.0, "正解はどれでしょう？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 2, 0, 1, 0, 2, 1, 13110403, "vo_minigame_1012_start_117", 1104, 1, 0.0, "正解は一つよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 1, 0, 3, 0, 1, 1, 13110404, "vo_minigame_1012_start_118", 1104, 3, 0.0, "どっちかしら？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 1, 0, 2, 0, 1, 1, 13110405, "vo_minigame_1012_start_119", 1104, 2, 0.0, "迷った時は運任せよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 1, 0, 5, 0, 1, 1, 13110406, "vo_minigame_1012_start_120", 1104, 5, 0.0, "〇？　それとも×？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 3, 0, 1, 0, 3, 1, 13110407, "vo_minigame_1012_start_121", 1104, 1, 0.0, "いくつか選びなさい");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 3, 0, 0, 0, 3, 1, 13110408, "vo_minigame_1012_start_122", 1104, 0, 0.0, "答えは複数あるわ！");
