INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 10, 1, 0, 0, 10, 2, 21300101, "vo_minigame_1012_result_2000", 3001, 6, 3.32, "すご、全部〇じゃん…！\nこの調子で教えてくれたら\nうちも頭よくなりそー！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 10, 1, 2, 3, 10, 2, 21300102, "vo_minigame_1012_result_2001", 3001, 6, 6.5, "え、〇しかなかった…？\n満点ってほんとにあるんだ…\nヒデサイマジすごい…！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 10, 1, 6, 5, 10, 2, 21300103, "vo_minigame_1012_result_2002", 3001, 3, 3.1, "満点じゃん！　やりー！\nもしかしてヒデサイには\n簡単過ぎた感じ？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 10, 2, 2, 11, 10, 2, 21300104, "vo_minigame_1012_result_2003", 3001, 3, 2.06, "ビシッと決まったね！\nヒデサイ、ベンキョー\n教えてくれてありがとー♪");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 10, 2, 7, 0, 10, 2, 21300105, "vo_minigame_1012_result_2004", 3001, 3, 4.45, "ムズい問題もぜーんぶ正解！\n激アツじゃん！\nヒデサイ、頭よすぎ～");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 10, 2, 2, 11, 10, 2, 21300106, "vo_minigame_1012_result_2005", 3001, 2, 0.01, "きゃはっ、満点じゃん！\n一緒にベンキョーしてる\nうちまでいい気分！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 10, 3, 3, 11, 10, 2, 21300107, "vo_minigame_1012_result_2006", 3001, 2, 6.64, "ヒデサイ、満点パーフェクト！\nこれで、もーサイツヨだね！\nそれっ、ハイタッチ～！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 10, 3, 6, 0, 10, 2, 21300108, "vo_minigame_1012_result_2007", 3001, 6, 0.0, "カンペキ過ぎて\nまぶしぃんですけど！\n〇しかないってどゆこと！？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 10, 3, 7, 0, 10, 2, 21300109, "vo_minigame_1012_result_2008", 3001, 6, 5.76, "おにムズでも満点じゃん…！\nヒデサイセンセーマジすごい！\nこれからも頼りにしてるよ～");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 9, 1, 6, 0, 7, 2, 21300110, "vo_minigame_1012_result_2009", 3001, 6, 0.0, "ヒデサイ、もしかして\nよゆーな感じ？\n正解しまくりじゃん！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 9, 1, 7, 0, 7, 2, 21300111, "vo_minigame_1012_result_2010", 3001, 2, 2.59, "〇いっぱいで、わろ～\nてかヒデサイ教えるのうまっ！\nめちゃわかりやすかったよ♪");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 9, 1, 3, 11, 7, 2, 21300112, "vo_minigame_1012_result_2011", 3001, 2, 4.09, "これだけ〇あったら、\nめちゃ気持ちいいね♪\n次は満点取っちゃおー！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 9, 2, 3, 0, 7, 2, 21300113, "vo_minigame_1012_result_2012", 3001, 2, 2.47, "満点まで、もーすぐじゃん！\nさっすがヒデサイ！\nバイブス上がってきた～");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 9, 2, 3, 11, 7, 2, 21300114, "vo_minigame_1012_result_2013", 3001, 3, 0.01, "きゃはっ、めちゃ解けてる～\nもー次は満点っしょ！\nテンアゲしてきたね♪");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 9, 2, 2, 0, 7, 2, 21300115, "vo_minigame_1012_result_2014", 3001, 2, 0.0, "ヒデサイのおかげで\nうちもちょっちベンキョー\nわかってきたかも！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 9, 3, 2, 0, 7, 2, 21300116, "vo_minigame_1012_result_2015", 3001, 6, 3.45, "おにムズ問題も\n〇ばっかじゃん…！\nヒデサイ、マジ心強い！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 9, 3, 3, 0, 7, 2, 21300117, "vo_minigame_1012_result_2016", 3001, 3, 0.0, "ヒデサイセンセーに\n追いつけ追い越せ！\nうちもがんばる～！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 9, 3, 3, 0, 7, 2, 21300118, "vo_minigame_1012_result_2017", 3001, 2, 4.0, "おにムズ問題も\nあとちょいで満点じゃん！\nもーここまできたら\nやるしかないっしょ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 6, 1, 0, 0, 4, 2, 21300119, "vo_minigame_1012_result_2018", 3001, 6, 0.92, "お！　あと半分だし\nうちも、もうちっと\nがんばってみるね！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 6, 1, 3, 0, 4, 2, 21300120, "vo_minigame_1012_result_2019", 3001, 0, 4.36, "まだイミフな問題あるけど\n悪くないよね？\nバイブス上がってきたし\n次もっとイケんじゃない？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 6, 1, 2, 0, 4, 2, 21300121, "vo_minigame_1012_result_2020", 3001, 6, 2.35, "だいたい半分ぐらい？\nじゃあ、こっからだね！\n集中、集中！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 6, 2, 2, 0, 4, 2, 21300122, "vo_minigame_1012_result_2021", 3001, 0, 2.13, "これで半分ぐらい？\nよしっ、とりま赤点回避！\nやりー！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 6, 2, 2, 0, 4, 2, 21300123, "vo_minigame_1012_result_2022", 3001, 0, 2.38, "あともう半分だね！\nフレッフレッ、ヒデサイ！\nうちもがんばる～！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 6, 2, 0, 0, 4, 2, 21300124, "vo_minigame_1012_result_2023", 3001, 4, 3.5, "う～ん、やっぱムズいね\nでも、半分ぐらい〇だし\nイケそーな気するね！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 6, 3, 6, 0, 4, 2, 21300125, "vo_minigame_1012_result_2024", 3001, 0, 2.25, "だいたい半分正解？\nとゆーことは\nあと半分で満点じゃん！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 6, 3, 6, 0, 4, 2, 21300126, "vo_minigame_1012_result_2025", 3001, 3, 2.14, "やるじゃんヒデサイ！\nえ？　もっと上目指すの？\nじゃあうちもがんばる！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 6, 3, 2, 0, 4, 2, 21300127, "vo_minigame_1012_result_2026", 3001, 6, 3.75, "おにムズだったのに\n半分解けてる…！？\nヒデサイいい感じ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3, 1, 10, 5, 1, 2, 21300128, "vo_minigame_1012_result_2027", 3001, 4, 2.53, "おにムズだったね～\n…え？　これって簡単なの？\nえへへ、うそだ～？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3, 1, 4, 9, 1, 2, 21300129, "vo_minigame_1012_result_2028", 3001, 4, 0.01, "…ねーねー、ヒデサイ\nうちに合わせて\n悪い点取らなくていいんだよ？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3, 1, 3, 0, 1, 2, 21300130, "vo_minigame_1012_result_2029", 3001, 0, 2.93, "ウォーミングアップは\nこんなところで…\nヒデサイ、次は\n本気出しちゃおうよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3, 2, 3, 4, 1, 2, 21300131, "vo_minigame_1012_result_2030", 3001, 0, 4.26, "あ、ヒデサイ\nうちと点数おそろじゃん！\n一緒に赤点取っちゃおっか～♪");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3, 2, 10, 0, 1, 2, 21300132, "vo_minigame_1012_result_2031", 3001, 10, 0.0, "えーっと…\nもっかい教えてくれたら\n次はもうちょい\nイケる気するよっ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3, 2, 0, 5, 1, 2, 21300133, "vo_minigame_1012_result_2032", 3001, 9, 4.98, "うちもさっぱりだった～\nどこ間違えたんだろ…？\nもっかいベンキョーしてみる？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3, 3, 4, 9, 1, 2, 21300134, "vo_minigame_1012_result_2033", 3001, 4, 0.01, "おにムズ過ぎてマジさっぱり…\nどーしよ…\nヒデサイ、助けて～");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3, 3, 4, 6, 1, 2, 21300135, "vo_minigame_1012_result_2034", 3001, 4, 0.01, "赤点って感じ？\nう～ん…せっかくだし\nうちと一緒にがんばろ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3, 3, 10, 11, 1, 2, 21300136, "vo_minigame_1012_result_2035", 3001, 4, 2.51, "やっぱムズいね…\nでも０点じゃないし\nオーライっしょ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 0, 1, 6, 0, 0, 2, 21300137, "vo_minigame_1012_result_2036", 3001, 0, 2.54, "よし、結果は…\nって０ってマ！？\nヒデサイ、どーしちゃったの？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 0, 1, 10, 5, 0, 2, 21300138, "vo_minigame_1012_result_2037", 3001, 2, 4.08, "ヒデサイ\nわざと０点取ったっしょ？\n違うの？　ほんとに～？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 0, 1, 4, 0, 0, 2, 21300139, "vo_minigame_1012_result_2038", 3001, 6, 3.41, "ヒデサイ、０点だね…\nうちが代わりに\nベンキョー教えてあげよっか…？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 0, 2, 8, 0, 0, 2, 21300140, "vo_minigame_1012_result_2039", 3001, 10, 4.1, "んーっと…\nぜんぜんわかんなかった！\nでも、ベンキョーって\nいつもそーだよね！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 0, 2, 2, 4, 0, 2, 21300141, "vo_minigame_1012_result_2040", 3001, 6, 5.8, "これ、うちら習ったっけ？\nヒデサイも覚えてない感じ？\nじゃあ仕方ないっしょ！\n次いこ次！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 0, 2, 8, 3, 0, 2, 21300142, "vo_minigame_1012_result_2041", 3001, 10, 4.6, "ねねね、全部×って\nこれはこれでレアなんじゃ？\n喜んじゃダメ？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 0, 3, 2, 0, 0, 2, 21300143, "vo_minigame_1012_result_2042", 3001, 10, 6.04, "おにムズってのはわかった！\nこれも一歩前進…だよね？\n次がんばろーよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 0, 3, 3, 4, 0, 2, 21300144, "vo_minigame_1012_result_2043", 3001, 9, 1.92, "０点…！　でもでも\nうちらバイブスは満点じゃん♪\nヒデサイ、もっかいやろ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 0, 3, 7, 0, 0, 2, 21300145, "vo_minigame_1012_result_2044", 3001, 7, 0.0, "ヒデサイと同じ点数\nちょっちうれしーかも？\n一緒に０からがんばろーね！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 0, 0, 2, 0, 0, 2, 22120101, "vo_minigame_1012_correct_232", 1201, 2, 0.0, "えへへ～");
