INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, -1, 1, 3, 4, 20, 2, 22300101, "vo_minigame_1012_result_2045", 3001, 2, 2.81, "〇多すぎてわろ～\nスラスラ解いてくし\nまじカッコよかったよ♪");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, -1, 1, 2, 11, 20, 2, 22300102, "vo_minigame_1012_result_2046", 3001, 3, 2.31, "点数イケイケじゃん！　\nもしかして、ヒデサイには\n簡単過ぎた感じ？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, -1, 1, 3, 11, 20, 2, 22300103, "vo_minigame_1012_result_2047", 3001, 3, 0.01, "きゃはっ、もうバッチリだね♪\n他の問題も教えてほしーし\n次はムズいのいっちゃう？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, -1, 2, 7, 11, 20, 2, 22300104, "vo_minigame_1012_result_2048", 3001, 6, 4.33, "ムズい問題なのに\n〇でいっぱいじゃん…！\nさっすが、ヒデサイセンセー！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, -1, 2, 2, 0, 20, 2, 22300105, "vo_minigame_1012_result_2049", 3001, 6, 5.73, "一緒にベンキョー\nしてるだけなのに\nうちまで賢くなった気する…！\nマジありがとね");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, -1, 2, 6, 8, 20, 2, 22300106, "vo_minigame_1012_result_2050", 3001, 6, 0.01, "これってムズい問題だよね？\nなんで簡単に解いてくの？\nヒデサイ、すごすぎ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, -1, 3, 3, 0, 20, 2, 22300107, "vo_minigame_1012_result_2051", 3001, 6, 4.02, "おにムズなのに\n答えるの一瞬だったね…！\nヒデサイ、頭良すぎじゃん？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, -1, 3, 3, 11, 20, 2, 22300108, "vo_minigame_1012_result_2052", 3001, 2, 5.24, "まる、まる、はなまる～\nきゃははっ、すごっ！\nさっすがヒデサイ！\nハイタッチー！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, -1, 3, 3, 4, 20, 2, 22300109, "vo_minigame_1012_result_2053", 3001, 2, 4.6, "これだけ教えてもらったら\nもうテストもよゆーっしょ！\nヒデサイ、マジありがとね♪");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, -1, 1, 10, 0, 20, 2, 22300110, "vo_minigame_1012_result_2054", 3001, 6, 5.57, "うちこんなの初めて見た…！\nヒデサイセンセー、神ってる！\nそだ、記念にこれ飾っとこうよ♪\nえ、それはちょっち恥ずかしい？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, -1, 2, 10, 0, 20, 2, 22300112, "vo_minigame_1012_result_2054", 3001, 6, 5.57, "うちこんなの初めて見た…！\nヒデサイセンセー、神ってる！\nそだ、記念にこれ飾っとこうよ♪\nえ、それはちょっち恥ずかしい？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, -1, 3, 10, 0, 20, 2, 22300114, "vo_minigame_1012_result_2054", 3001, 6, 5.57, "うちこんなの初めて見た…！\nヒデサイセンセー、神ってる！\nそだ、記念にこれ飾っとこうよ♪\nえ、それはちょっち恥ずかしい？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 19, 1, 2, 0, 15, 2, 22300116, "vo_minigame_1012_result_2056", 3001, 2, 0.0, "めちゃ問題あったのに\nバンバン答えてくし\n超頼もしかった！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 19, 1, 3, 11, 15, 2, 22300117, "vo_minigame_1012_result_2057", 3001, 6, 5.23, "おーさすがヒデサイ！\n〇の数も超ヒデサイだね♪\nイェーイ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 19, 1, 2, 11, 15, 2, 22300118, "vo_minigame_1012_result_2058", 3001, 3, 3.23, "ヒデサイ、〇でいっぱいじゃん♪\nうちも教えてもらったとこは\nけっこー覚えてきたかも？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 19, 2, 7, 10, 15, 2, 22300119, "vo_minigame_1012_result_2059", 3001, 3, 6.0, "アゲアゲな点数じゃん！\nとりま、どやっとく？\nせーの、どやぁ…！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 19, 2, 7, 0, 15, 2, 22300120, "vo_minigame_1012_result_2060", 3001, 7, 0.0, "ムズい問題も\nだんだん解けてくると\nたのしーね\nちょっち感動～");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 19, 2, 6, 0, 15, 2, 22300121, "vo_minigame_1012_result_2061", 3001, 6, 0.0, "たくさん解いても\nヒデサイは頭パンクしないの？\nスゴ…！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 19, 3, 2, 3, 15, 2, 22300122, "vo_minigame_1012_result_2062", 3001, 6, 3.06, "わわっ、〇ばっかり…！\nこの調子なら\n次は20に届くんじゃない？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 19, 3, 5, 0, 15, 2, 22300123, "vo_minigame_1012_result_2063", 3001, 6, 5.74, "15個以上〇って…！\nおにムズなのに、すごすぎ～\nうちもがんばらなきゃ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 19, 3, 3, 0, 15, 2, 22300124, "vo_minigame_1012_result_2064", 3001, 6, 2.67, "すっごい集中力…！\nもしかして、ヒデサイ\nおにムズ問題ほど\n燃える感じっしょ？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 14, 1, 3, 0, 10, 2, 22300131, "vo_minigame_1012_result_2067", 3001, 3, 0.0, "きゃはっ、いい感じ！\nたくさん解けてるし\nベンキョーの成果\n…ってやつだね♪");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 14, 1, 2, 0, 10, 2, 22300132, "vo_minigame_1012_result_2068", 3001, 2, 0.0, "10個以上〇だね♪\nヒデサイのおかげで\nうちも、ちょっち\n頭よくなったかな？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 14, 1, 2, 0, 10, 2, 22300133, "vo_minigame_1012_result_2069", 3001, 10, 2.28, "けっこー解けたよね？\nやっぱ〇増えると\nバイブス上がる～");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 14, 2, 2, 0, 10, 2, 22300134, "vo_minigame_1012_result_2070", 3001, 2, 0.0, "ベンキョーってあれだね\nわかった気すると\nまあまあたのしーかも！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 14, 2, 2, 0, 10, 2, 22300135, "vo_minigame_1012_result_2071", 3001, 6, 2.1, "10個以上解けてる！？\nけっこーいいペースだよね？\nいい調子、いい調子～");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 14, 2, 3, 0, 10, 2, 22300136, "vo_minigame_1012_result_2072", 3001, 2, 2.13, "けっこー解けてる！\nムズい問題もヒデサイと\n一緒なら怖くないね♪");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 14, 3, 7, 0, 10, 2, 22300137, "vo_minigame_1012_result_2073", 3001, 7, 0.0, "おにムズ問題でも教えるの\n超やさしーし、マジ感謝！\n一緒にがんばろーね♪");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 14, 3, 6, 0, 10, 2, 22300138, "vo_minigame_1012_result_2074", 3001, 6, 0.0, "おにムズなのに\n〇けっこーあるし\nヒデサイすごくない？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 14, 3, 5, 0, 10, 2, 22300139, "vo_minigame_1012_result_2075", 3001, 6, 4.21, "おにムズでこのペースは\nすごいんじゃ…？\nうちもがんばってついてくね！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 9, 1, 3, 0, 5, 2, 22300146, "vo_minigame_1012_result_2078", 3001, 0, 1.94, "悪くないよね？\nでもでも\nヒデサイとうちなら\nもっとできる気する！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 9, 1, 0, 0, 5, 2, 22300147, "vo_minigame_1012_result_2079", 3001, 4, 2.28, "もっと〇ほしーね…\n地道にやるしか\nないっぽいし\nもっかい教えてくれる？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 9, 1, 4, 0, 5, 2, 22300148, "vo_minigame_1012_result_2080", 3001, 4, 0.0, "ベンキョーしたけど\nわかんないとこばっか…\nヒデサイセンセー、助けて～");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 9, 2, 3, 0, 5, 2, 22300149, "vo_minigame_1012_result_2081", 3001, 4, 2.67, "やっぱムズかったね…\nでも次はもうちょい\nできそーな気がするよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 9, 2, 6, 0, 5, 2, 22300150, "vo_minigame_1012_result_2082", 3001, 10, 4.68, "問題ムズいし、この点数は\nありよりのありっしょ？\nえ、もっとできた感じ？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 9, 2, 9, 0, 5, 2, 22300151, "vo_minigame_1012_result_2083", 3001, 9, 0.0, "どこ間違ったんだろ？\nうちさっぱりだった…\nやっぱムズいだけあるね");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 9, 3, 3, 0, 5, 2, 22300152, "vo_minigame_1012_result_2084", 3001, 0, 3.55, "激ムズだけど\nやることは一緒だよね？\nうちもヒデサイについてくから\nコツコツがんばろ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 9, 3, 6, 0, 5, 2, 22300153, "vo_minigame_1012_result_2085", 3001, 4, 2.51, "やっぱおにムズだね…\nそだ、迷ったら\nヒント使うのも\nありよりのあり？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 9, 3, 5, 0, 5, 2, 22300154, "vo_minigame_1012_result_2086", 3001, 9, 6.15, "やっぱテストって\nなんとなくじゃ無理？\n覚えるしかないの？\nじゃあがんばるしかないね…");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 4, 1, 9, 6, 1, 2, 22300155, "vo_minigame_1012_result_2087", 3001, 4, 4.12, "できたと思ったけど\nそーじゃなかった系？\nテストってマジきびしー…");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 4, 1, 4, 6, 1, 2, 22300156, "vo_minigame_1012_result_2088", 3001, 4, 0.01, "うーん…さっぱり！\nでも簡単な問題なんだよね…？\nもっかいやってみる？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 4, 1, 3, 0, 1, 2, 22300157, "vo_minigame_1012_result_2089", 3001, 0, 5.28, "うちらまだまだ\nベンキョーちうだし…\nこれからだよねっ？\nね、ヒデサイ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 4, 2, 3, 0, 1, 2, 22300158, "vo_minigame_1012_result_2090", 3001, 0, 2.89, "ちょっとずつ覚えれば\nおーけーっしょ！\nうちと一緒に\nベンキョーだね！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 4, 2, 7, 0, 1, 2, 22300159, "vo_minigame_1012_result_2091", 3001, 0, 5.45, "うちベンキョー苦手でも\nヒデサイとベンキョー\nするのは好き！　だから\nもっかい教えてくれる？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 4, 2, 10, 3, 1, 2, 22300160, "vo_minigame_1012_result_2092", 3001, 4, 4.29, "覚えても、すぐ忘れるんだけど\nどしたらいい？\nあ、そーゆうとき\nフクシューする感じ？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 4, 3, 8, 6, 1, 2, 22300161, "vo_minigame_1012_result_2093", 3001, 4, 4.64, "ムズ過ぎ！\n頭パンクするかと思った…！\nヒデサイ、うちの頭\nふぅふぅして～");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 4, 3, 5, 0, 1, 2, 22300162, "vo_minigame_1012_result_2094", 3001, 9, 3.14, "おにムズ過ぎてテンサゲ～\nでもヒデサイがんばってるし\nうちもがんばる！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 4, 3, 4, 0, 1, 2, 22300163, "vo_minigame_1012_result_2095", 3001, 7, 6.59, "ヒデサイと同じ点数で\nちょっち安心したかも\n一緒にがんばろーね！\n置いてっちゃやだよ？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 0, 1, 3, 0, 0, 2, 22300164, "vo_minigame_1012_result_2096", 3001, 3, 0.0, "…まあ、これより下はないし\n次は大逆転\n点数爆上がりっしょ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 0, 1, 10, 5, 0, 2, 22300165, "vo_minigame_1012_result_2097", 3001, 9, 2.2, "０点じゃん…\nそだ、次はえんぴつ転がして\n選ぶ作戦やってみる？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 0, 1, 4, 6, 0, 2, 22300166, "vo_minigame_1012_result_2098", 3001, 4, 0.01, "考えるの無理な時あるよね…\nヒデサイもそーゆう\n感じだったの？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 0, 2, 2, 3, 0, 2, 22300167, "vo_minigame_1012_result_2099", 3001, 6, 2.8, "え、ヒデサイも０点？\nじゃあうちと一緒じゃん♪\nまあ焦んないで\nベンキョーしてこーよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 0, 2, 4, 6, 0, 2, 22300168, "vo_minigame_1012_result_2100", 3001, 9, 3.22, "むむむ～…０点…！\n覚えてもすぐ忘れちゃうし\nベンキョーってマジ大変");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 0, 2, 0, 11, 0, 2, 22300169, "vo_minigame_1012_result_2101", 3001, 4, 2.1, "０点だね…\nでも、へーきへーき\nリベンジしたら、結果オーライ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 0, 3, 2, 3, 0, 2, 22300170, "vo_minigame_1012_result_2102", 3001, 0, 2.74, "おやつ休憩して\nリベンジしよっ！\n甘いの食べたら、イケるっしょ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 0, 3, 9, 9, 0, 2, 22300171, "vo_minigame_1012_result_2103", 3001, 6, 3.0, "ヒデサイでも\nおにムズな感じ？\nじゃあ、このテスト\n誰も解けなくない？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 0, 3, 2, 0, 0, 2, 22300172, "vo_minigame_1012_result_2104", 3001, 10, 4.37, "…あれ？\n０が〇に見えてきた！\nきゃはっ、ちょっち\nやる気出てきたかも！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 0, 0, 0, 10, 0, 2, 23100101, "vo_minigame_1012_gamestart_200", 1001, 0, 0.01, "よーし、がんばるぞー");
